"use client";

import { useMemo, useState } from "react";
import {
  EXAMS,
  computeQuestionAnalytics,
  percentileRank,
  trainingRecommendations,
  getExam,
  type AttemptQuestionScore,
  type QuestionAnalytics,
  type TrainingRecommendation,
} from "@/lib/marketing-tests/exams";
import type { ExamResult } from "@/components/marketing/ExamCertificate";
import { Card, Button, Badge, Select, SelectItem } from "@/components/marketing/ui";

interface AnswerRecord {
  questionId: string;
  type: string;
  selected: number | number[];
  correct: number | number[];
  skill: string;
  difficulty: number;
  isCorrect: boolean;
  earnedWeight: number;
  maxWeight: number;
}

function findQuestionPrompt(examId: string, questionId: string): string {
  const exam = getExam(examId);
  if (!exam) return questionId;
  const q = exam.questions.find((qq) => qq.id === questionId);
  return q ? q.prompt : questionId;
}

function truncate(text: string, max: number): string {
  return text.length > max ? text.slice(0, max - 1) + "…" : text;
}

function discriminationColor(d: number): string {
  if (d >= 0.3) return "text-green-600";
  if (d >= 0.2) return "text-amber-600";
  return "text-red-600";
}

export function ExamAnalytics({
  history,
  onBack,
  onViewAttempt,
}: {
  history: ExamResult[];
  onBack: () => void;
  onViewAttempt: (a: ExamResult) => void;
}) {
  const [examFilter, setExamFilter] = useState<string>("all");

  const examIds = useMemo(() => {
    const ids = new Set<string>();
    for (const r of history) ids.add(r.examId);
    return Array.from(ids);
  }, [history]);

  const filtered = useMemo(() => {
    if (examFilter === "all") return history;
    return history.filter((r) => r.examId === examFilter);
  }, [history, examFilter]);

  const scores = useMemo<AttemptQuestionScore[]>(() => {
    const out: AttemptQuestionScore[] = [];
    for (const r of filtered) {
      const answers = r.answers as AnswerRecord[];
      for (const ar of answers) {
        out.push({
          attemptId: r.attemptId,
          questionId: ar.questionId,
          examId: r.examId,
          earnedFraction: ar.maxWeight > 0 ? ar.earnedWeight / ar.maxWeight : 0,
          isCorrect: ar.isCorrect,
          weightedPercentage: r.percentage,
        });
      }
    }
    return out;
  }, [filtered]);

  const analytics = useMemo<QuestionAnalytics[]>(
    () => computeQuestionAnalytics(scores),
    [scores]
  );

  const mostRecent = useMemo(() => {
    let best: ExamResult | undefined;
    for (const r of filtered) {
      if (!best || r.takenAt > best.takenAt) best = r;
    }
    return best;
  }, [filtered]);

  const percentile = useMemo(() => {
    if (!mostRecent) return null;
    return percentileRank(
      mostRecent.percentage,
      filtered.map((a) => a.percentage)
    );
  }, [mostRecent, filtered]);

  const recommendations = useMemo<TrainingRecommendation[]>(() => {
    if (!mostRecent) return [];
    return trainingRecommendations(mostRecent.skillBreakdown);
  }, [mostRecent]);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold">Exam Analytics</h2>
          <p className="text-sm text-muted-foreground">
            Question-level item analysis and training recommendations.
          </p>
        </div>
        <Button variant="outline" onClick={onBack}>
          Back
        </Button>
      </div>

      <Card className="p-4">
        <div className="flex items-center gap-3">
          <span className="text-sm font-medium">Exam:</span>
          <Select value={examFilter} onValueChange={setExamFilter}>
            <SelectItem value="all">All exams</SelectItem>
            {examIds.map((id) => {
              const ex = getExam(id);
              return (
                <SelectItem key={id} value={id}>
                  {ex ? ex.title : id}
                </SelectItem>
              );
            })}
          </Select>
          <span className="ml-auto text-sm text-muted-foreground">
            {filtered.length} attempt{filtered.length === 1 ? "" : "s"}
          </span>
        </div>
      </Card>

      <Card className="p-4">
        <h3 className="mb-3 text-lg font-semibold">Question Item Analysis</h3>
        {scores.length === 0 ? (
          <p className="text-sm text-muted-foreground">No attempts to analyze yet.</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b text-left">
                  <th className="py-2 pr-4">Question</th>
                  <th className="py-2 pr-4">p-value</th>
                  <th className="py-2 pr-4">Discrimination</th>
                  <th className="py-2 pr-4">Attempts</th>
                  <th className="py-2 pr-4">Avg earned</th>
                </tr>
              </thead>
              <tbody>
                {analytics.map((a) => (
                  <tr key={`${a.examId}-${a.questionId}`} className="border-b">
                    <td className="py-2 pr-4 max-w-md">
                      {truncate(findQuestionPrompt(a.examId, a.questionId), 80)}
                    </td>
                    <td className="py-2 pr-4">{(a.pValue * 100).toFixed(1)}%</td>
                    <td className={`py-2 pr-4 font-medium ${discriminationColor(a.discriminationIndex)}`}>
                      {a.discriminationIndex.toFixed(2)}
                    </td>
                    <td className="py-2 pr-4">{a.attempts}</td>
                    <td className="py-2 pr-4">{(a.avgEarnedFraction * 100).toFixed(1)}%</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      {mostRecent && percentile !== null && (
        <Card className="p-4">
          <h3 className="mb-2 text-lg font-semibold">Percentile Ranking</h3>
          <p className="text-sm">
            You scored higher than{" "}
            <span className="font-semibold">{percentile.toFixed(0)}%</span> of
            candidates on this exam.
          </p>
        </Card>
      )}

      {mostRecent && (
        <Card className="p-4">
          <div className="mb-3 flex items-center justify-between">
            <h3 className="text-lg font-semibold">Training Recommendations</h3>
            <Button variant="ghost" onClick={() => onViewAttempt(mostRecent)}>
              View latest attempt
            </Button>
          </div>
          {recommendations.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              No recommendations available.
            </p>
          ) : (
            <ul className="space-y-3">
              {recommendations.map((rec) => (
                <li
                  key={rec.skill}
                  className="rounded-md border p-3"
                >
                  <div className="flex flex-wrap items-center gap-2">
                    <span className="font-medium">
                      {rec.skill.replace(/-/g, " ").replace(/\b\w/g, (c) =>
                        c.toUpperCase()
                      )}
                    </span>
                    <span className="text-sm text-muted-foreground">
                      {rec.scorePct.toFixed(0)}%
                    </span>
                    <Badge variant="secondary">{rec.band.band}</Badge>
                  </div>
                  <p className="mt-1 text-sm">{rec.recommendation}</p>
                  {rec.suggestedExams.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5">
                      {rec.suggestedExams.map((id) => {
                        const ex = getExam(id);
                        return (
                          <Badge key={id} variant="outline">
                            {ex ? ex.title : id}
                          </Badge>
                        );
                      })}
                    </div>
                  )}
                </li>
              ))}
            </ul>
          )}
        </Card>
      )}
    </div>
  );
}

void EXAMS;
EOF
